#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char buf[1005];
    while (T--) {
        if (!fgets(buf, sizeof(buf), stdin)) break;
        size_t len = strlen(buf);
        if (len && buf[len-1] == '\n') buf[--len] = '\0';
        for (size_t i = 0; i < len; ++i) {
            if (i % 2 == 0) putchar(toupper((unsigned char)buf[i]));
            else putchar(tolower((unsigned char)buf[i]));
        }
        putchar('\n');
    }
    return 0;
}

