#!/usr/bin/env python3
import sys

def alternating_case(s: str) -> str:
    return ''.join(c.upper() if i % 2 == 0 else c.lower() for i, c in enumerate(s))

lines = sys.stdin.read().splitlines()
if not lines:
    sys.exit()
T = int(lines[0])
for i in range(1, T + 1):
    s = lines[i]
    print(alternating_case(s))

